// ---------------------------------------------------------------
// Process: SC_METHOD wait_for_end
// Static sensitivity: sensitive << clk.pos() << testbench_end_event;

void mc_testbench::wait_for_end() {
   // If run() has not finished, we do nothing here
   if (!testbench_ended) return;
   // check for completed outputs
   if (dout_comp->get_compare_count() < dout_capture_count) {testbench_end_event.notify(1,SC_NS); return;}
   // If we made it here, all outputs have flushed. Check the results
   SC_REPORT_INFO(name(), "Simulation completed");
   check_results();
   sc_stop();
}
// ---------------------------------------------------------------
// Process: SC_THREAD run
// Static sensitivity: 

void mc_testbench::run() {
   testbench::enable_idle_sync_mode = false;
   testbench::idle_sync_stable_cycles = 1;
   testbench::din_ignore = false;
   testbench::din_skip = false;
   testbench::din_skip_quiet = false;
   testbench::din_skip_once = false;
   testbench::din_skip_noerr = false;
   testbench::din_array_comp_first = -1;
   testbench::din_array_comp_last = -1;
   testbench::din_wait_ctrl.clear();
   din_capture_count = 0;
   din_iteration_count = 0;
   testbench::offset_ignore = false;
   testbench::offset_skip = false;
   testbench::offset_skip_quiet = false;
   testbench::offset_skip_once = false;
   testbench::offset_skip_noerr = false;
   testbench::offset_array_comp_first = -1;
   testbench::offset_array_comp_last = -1;
   testbench::offset_wait_ctrl.clear();
   offset_capture_count = 0;
   offset_iteration_count = 0;
   testbench::dout_ignore = false;
   testbench::dout_skip = false;
   testbench::dout_skip_quiet = false;
   testbench::dout_skip_once = false;
   testbench::dout_skip_noerr = false;
   testbench::dout_array_comp_first = -1;
   testbench::dout_array_comp_last = -1;
   testbench::dout_use_mask = false;
   testbench::dout_output_mask = ~0;
   testbench::dout_wait_ctrl.clear();
   dout_capture_count = 0;
   dout_iteration_count = 0;
   testbench testbench_inst(sc_argc(), sc_argv());
   main_exit_code = testbench_inst.main();
   cout<<"Info: Execution of user-supplied C++ testbench 'main()' has completed with exit code = " << main_exit_code << endl;
   cout<<endl;
   cout<<"Info: Collecting data completed"<<endl;
   cout<<"   captured "<<din_capture_count<<" values of din"<<endl;
   cout<<"   captured "<<offset_capture_count<<" values of offset"<<endl;
   cout<<"   captured "<<dout_capture_count<<" values of dout"<<endl;
   testbench_ended = true;
   testbench_end_event.notify(SC_ZERO_TIME);
}
